import{_ as e,c as r,l as t,a as o,t as i,a4 as d,o as _}from"./chunks/framework.CzsDe1xi.js";const b=JSON.parse('{"title":"ReadView","description":"","frontmatter":{"title":"ReadView"},"headers":[],"relativePath":"doc/数据库/Mysql/基础/事务/读视图.md","filePath":"packages/doc/src/数据库/Mysql/基础/事务/读视图.md","lastUpdated":1711354439000}'),p={name:"doc/数据库/Mysql/基础/事务/读视图.md"},l={id:"frontmatter-title",tabindex:"-1"},n=t("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":'Permalink to "{{ $frontmatter.title }}"'},"​",-1),s=d('<h2 id="_1-目的" tabindex="-1">1.目的 <a class="header-anchor" href="#_1-目的" aria-label="Permalink to &quot;1.目的&quot;">​</a></h2><p>1.视图只在RR和RC级别存在</p><p>2.在每个事务开启的时候都会创建一个 ReadView 视图，作用就是用来记录每个事务中的操作的一些 Undo Log 记录。方便判断undo log中哪些数据可以被当前事务所读取。</p><p>3.数据快照，快照读</p><h2 id="_2-涉及到的字段" tabindex="-1">2.涉及到的字段 <a class="header-anchor" href="#_2-涉及到的字段" aria-label="Permalink to &quot;2.涉及到的字段&quot;">​</a></h2><p>1.m_ids：开启视图的时候，用于记录活跃中的事务的 ID</p><p>2.min_trx_id：当前活跃的事务中的最小的事务 ID</p><p>3.max_trx_id：表示生成视图时，系统分配给下一个事务的 ID。<strong>注意这里并不是指的最大的事务 ID</strong>，这个事务一定是当前的 m_ids 中不存在的。（事务 ID 的生成是递增的）；</p><p>4.creator_trx_id：当前活跃事务的 ID；</p><h4 id="判断版本链数据是否可见逻辑" tabindex="-1">判断版本链数据是否可见逻辑： <a class="header-anchor" href="#判断版本链数据是否可见逻辑" aria-label="Permalink to &quot;判断版本链数据是否可见逻辑：&quot;">​</a></h4><p>执行select * from table;因为每一条记录都有几个隐藏字段：row_id,trx_id,roll_pointer</p><p>顺着roll_pointer到undo log中寻找可见版本，没有修改的话直接读取数据即可。</p><p>1.版本链的trx_id = creator_trx_id,可见，意味着当前事务在访问自己修改的记录</p><p>2.版本链的trx_id &lt; min_trx_id, 说明该事务已经不存在了，可以访问。（要么提交，要么回滚）</p><p>提交：undo log中会保留记录</p><p>回滚：undo log会在事务回滚之后删除对应的数据</p><p>所以只能是提交，肯定可见。</p><p>3.版本链的trx_id &gt;= max_trx_id, 访问的是未来事务修改的数据，不可见</p><p>4.版本链的trx_id 在min_trx_id 和max_trx_id之间</p><p>​ 1.在m_ids中，事务还没提交，不可见</p><p>​ 2.不在m_ids中，事务已提交，可见</p><h2 id="_3-readview-生成时机" tabindex="-1">3.Readview 生成时机 <a class="header-anchor" href="#_3-readview-生成时机" aria-label="Permalink to &quot;3.Readview 生成时机&quot;">​</a></h2><p>RR级别下：第一次执行查询语句时候生成，之后不再变化</p><p>RC级别下：每次执行查询语句都会生成最新的视图数据</p>',24);function c(a,h,m,x,f,u){return _(),r("div",null,[t("h1",l,[o(i(a.$frontmatter.title)+" ",1),n]),s])}const g=e(p,[["render",c]]);export{b as __pageData,g as default};
